import bisect


class SummaryRanges:
    def __init__(self):
        self.starts = []
        self.intervals = []
    def addNum(self, value):
        starts = self.starts
        iv = self.intervals
        i = bisect.bisect_right(starts, value)
        if i > 0 and iv[i - 1][1] >= value:
            return
        merge_left = i > 0 and iv[i - 1][1] == value - 1
        merge_right = i < len(iv) and iv[i][0] == value + 1
        if merge_left and merge_right:
            iv[i - 1][1] = iv[i][1]
            del iv[i]; del starts[i]
        elif merge_left:
            iv[i - 1][1] = value
        elif merge_right:
            iv[i][0] = value
            starts[i] = value
        else:
            starts.insert(i, value)
            iv.insert(i, [value, value])
    def getIntervals(self):
        return [list(p) for p in self.intervals]

