class SummaryRanges {
    constructor() {
        this.intervals = [];
    }
    addNum(value) {
        const iv = this.intervals;
        let lo = 0, hi = iv.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (iv[mid][0] <= value) lo = mid + 1; else hi = mid;
        }
        const i = lo;
        if (i > 0 && iv[i - 1][1] >= value) return;
        const mergeLeft = i > 0 && iv[i - 1][1] === value - 1;
        const mergeRight = i < iv.length && iv[i][0] === value + 1;
        if (mergeLeft && mergeRight) {
            iv[i - 1][1] = iv[i][1];
            iv.splice(i, 1);
        } else if (mergeLeft) {
            iv[i - 1][1] = value;
        } else if (mergeRight) {
            iv[i][0] = value;
        } else {
            iv.splice(i, 0, [value, value]);
        }
    }
    getIntervals() {
        return this.intervals.map(p => [p[0], p[1]]);
    }
}
